import copy


class RasterType:
    """
    Encapsulates raster type-specific input parameters for a dataset.

    Defines the set of accepted input parameters required for that type and
    exposes them as attributes on the instance.

    .. note::
        Users should not instantiate this class directly. ``RasterType`` objects
        are automatically created and managed using the :attr:`raster_type`
        attribute of an :class:`~arcgis.raster.ImageSource` instance.

    .. note::
        Certain attributes are specific to the selected raster type and will only be
        present when the *name* matches that raster type. Other attributes are
        common to all raster types and appear for every :class:`~arcgis.raster.RasterType`
        instance.

        Type-specific attributes are listed in the "Raster Type specific attributes"
        table below; common attributes are listed in the "Common Raster Type
        attributes" table.


    ====================================     ====================================================================
    **Parameter**                            **Description**
    ------------------------------------     --------------------------------------------------------------------
    name                                     Required string. Name of the raster type. This determines the attributes
                                             to be provided by the user.

                                             Choice list:

                                             | [
                                             | "ASTER", "Aerial", "DMCII", "DubaiSat-2", "Frame Camera", "GF-1 PMS", "GF-1 WFV", "GF-2 PMS",
                                             | "GRIB", "GeoEye-1", "HDF", "IKONOS", "Jilin-1", "KOMPSAT-2", "KOMPSAT-3", "Landsat 1-5 MSS",
                                             | "Landsat 4-5 TM", "Landsat 7 ETM+", "Landsat 8", "Landsat 9", "PlanetScope", "Pleiades NEO",
                                             | "Pleiades-1", "QuickBird", "RapidEye", "Raster Dataset", "SPOT 5", "SPOT 6", "SPOT 7"
                                             | "Sentinel-2", "SkySat", "Superview-1", "UAV/UAS", "WorldView-1", "WorldView-2", "WorldView-3",
                                             | "WorldView-4", "ZY3-CRESDA", "ZY3-SASMAC"
                                             | ]
    ====================================     ====================================================================

    +------------------------------------------------------------------------------------------------------------------------------------+
    |                                  Raster Type specific attributes                                                                   |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | **Attributes**                |                       **Description**                                                              |
    +===============================+====================================================================================================+
    | product_type                  | String. The type or level of the satellite product. For more information on the                    |
    |                               | specific products types supported for each raster type please see <Supported Raster Types>.        |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | pansharpen_type               | String. The type of pansharpening to be applied to the image source. For more information on the   |
    |                               | specific pansharpen types supported for each raster type please see <Supported Raster Types>.      |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | pansharpen_weights            | List. The weights to be used for pansharpening the image source. For more information on the       |
    |                               | specific pansharpen weights supported for each raster type please see <Supported Raster Types>.    |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | filter                        | String. Pansharpen filter. Possible filter values are:                                             |
    |                               | * None                                                                                             |
    |                               | * Sharpen                                                                                          |
    |                               | * SharpenMore                                                                                      |
    |                               | For more information on the specific pansharpen filters please see <Supported Raster Types>.       |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | gps_info                      | String, List. Path to the GPS file or gps list returned by read_camera_gps_info().                 |
    |                               | Required only if each image's GPS info is not embedded in the EXIF header.                         |
    |                               | Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).                   |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | camera_info                   | String, Dictionary. Path to the camera file or camera dictionary returned by                       |
    |                               | read_camera_gps_info(). Path can be a UNC file path or a datastore path                            |
    |                               | (eg. /fileShares, /cloudStores).                                                                   |
    +-------------------------------+----------------------------------------------------------------------------------------------------+

    +------------------------------------------------------------------------------------------------------------------------------------+
    |                                 Common Raster Type attributes                                                                      |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | **Attributes**                |                       **Description**                                                              |
    +===============================+====================================================================================================+
    | processing_template           | String. Name of the processing template to be applied to the raster type.                          |
    |                               | For more information on the specific processing templates supported for each raster type please    |
    |                               | see <Supported Raster Types> :func:arcgis.raster.analytics.create_image_collection                 |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | dem                           | String. A DEM used to provide an initial estimate of the flight  height for each image. Path can   |
    |                               | be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).                            |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | averagezdem                   | String. The average elevation to be read from the DEM provided. Default is                         |
    |                               | "https://elevation3d.arcgis.com/arcgis/rest/services/WorldElevation3D/Terrain3D/ImageServer"       |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | constant_z                    | Integer. A value, in meters, that is used to provide an initial estimate of the flight height      |
    |                               | for each image.                                                                                    |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | zfactor                       | Float. The scaling factor used to convert the elevation values. Only honored when using a DEM.     |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | zoffset                       | Float. The base value to be added to the elevation value in the DEM. This can be used to offset    |
    |                               | elevation values that do not start at sea level. Only honored when using a DEM.                    |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | correct_geoid                 | Boolean. If set to True, the geoid correction is applied to the elevation values in the DEM.       |
    |                               | Only honored when using a DEM.                                                                     |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | estimate_flight_height        | Boolean. If set to True, the flight height is estimated from the image metadata.                   |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | is_altitude_flight_height     | Boolean. A value that defines whether the drone reports heights relative to the takeoff point or   |
    |                               | altitude for heights relative to a vertical datum. False indicates altitude above a datum, and     |
    |                               | True indicates the altitude value is flight height from a takeoff point.                           |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | minimum_flight_height         | Integer. Minimum flight height. If the estimated flight height of an image is smaller than this    |
    |                               | number, the image will be considered invalid and will not be added to the image collection for     |
    |                               | future processing.                                                                                 |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | stretch_type                  | Dictionary. can be as follows:                                                                     |
    |                               |                                                                                                    |
    |                               | * "None"                                                                                           |
    |                               | * {"MinMax": [<min>, <max>]}                                                                       |
    |                               | * {"PercentMinMax": [<min_percent>, <max_percent>]}                                                |
    |                               | * {"StdDev": <number_of_standard_deviations>}                                                      |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | scale_factor                  | Float. The scale factor applied to the pixel values of the input raster.                           |
    +-------------------------------+----------------------------------------------------------------------------------------------------+
    | valid_range                   | List. The range of pixel values. [<MaskMinValue>, <MaskMaxValue>]                                  |
    +-------------------------------+----------------------------------------------------------------------------------------------------+

    """

    _raster_types_satellite_list = {
        "names": [
            "ASTER",
            "DMCII",
            "DubaiSat-2",
            "GeoEye-1",
            "GF-1 PMS",
            "GF-1 WFV",
            "GF-2 PMS",
            "GRIB",
            "HDF",
            "IKONOS",
            "Jilin-1",
            "KOMPSAT-2",
            "KOMPSAT-3",
            "Landsat 1-5 MSS",
            "Landsat 4-5 TM",
            "Landsat 7 ETM+",
            "Landsat 8",
            "Landsat 9",
            "PlanetScope",
            "Pleiades-1",
            "Pleiades NEO",
            "QuickBird",
            "RapidEye",
            "Sentinel-2",
            "SkySat",
            "SPOT 5",
            "SPOT 6",
            "SPOT 7",
            "Superview-1",
            "WorldView-1",
            "WorldView-2",
            "WorldView-3",
            "WorldView-4",
            "ZY3-SASMAC",
            "ZY3-CRESDA",
        ],
        "attributes": {
            "product_type": """ 
                       The type or level of the satellite product. For more information on the specific products types supported for each raster type please see <Supported Raster Types>.	
                       """,
            "pansharpen_type": """ 
                       The type of pansharpening to be applied to the image source. For more information on the specific pansharpen types supported for each raster type please see <Supported Raster Types>.	
                       """,
            "pansharpen_weights": """ 
                       The weights to be used for pansharpening the image source. For more information on the specific pansharpen weights supported for each raster type please see <Supported Raster Types>.	
                       """,
            "filter": """ 
                      Pansharpen filter. For more information on the specific pansharpen filters please see <Supported Raster Types>.	
                      """,
        },
    }

    _raster_types_aerial_list = {
        "Aerial": {
            "camera_info": """
                    Path to the frame camera info file. 
                    Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
                    """
        },
        "Frame Camera": {
            "camera_info": """
                    Path to the frame camera info file. 
                    Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
                    """
        },
        "UAV/UAS": {
            "camera_info": """
                    Camera information dictionary returned by read_camera_gps_info(). 
                    """,
            "gps_info": """
                    GPS information list returned by read_camera_gps_info(). 
                    Required only if each image's GPS info is not embedded in the EXIF header.
                    """,
        },
        # "ISAT": {
        #     "photo_file": """
        #          Required, Path to the ISAT photo file. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #          If byref is set to False, the file will be copied over to the rasterstore.
        #          """,
        #     "camera_info": """
        #          Required, Path to the ISAT camera file. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #          If byref is set to False, the file will be copied over to the rasterstore.
        #          """,
        #     "image_data_path": """
        #          Path to the folder containing the images to be added to the image collection. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #          If byref is set to False, the file will be copied over to the rasterstore.
        #          """,
        # },
        # "Match-AT": {
        #     "camera_info": """
        #              Required, Path to the Match-AT camera file. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #              If byref is set to False, the file will be copied over to the rasterstore.
        #              """,
        #     "image_data_path": """
        #              Path to the folder containing the images to be added to the image collection. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #              If byref is set to False, the file will be copied over to the rasterstore.
        #              """,
        # },
        # "MOD": {
        #     "image_data_path": """
        #         Path to the folder containing the images to be added to the image collection. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #         If byref is set to False, the file will be copied over to the rasterstore.
        #         """,
        #     "image_extension": """
        #         Extension of the input image files in the image folder (eg. .tif, .sid.).
        #         """,
        #     "pixel_size": """
        #         Pixel size in microns.
        #         """,
        # },
        # "PAR": {
        #     "image_data_path": """
        #         Path to the folder containing the images to be added to the image collection. Path can be a UNC file path or a datastore path (eg. /fileShares, /cloudStores).
        #         If byref is set to False, the file will be copied over to the rasterstore.
        #         """,
        #     "image_extension": """
        #         Extension of the input image files in the image folder (eg. .tif, .sid.).
        #         """,
        #     "pixel_size": """
        #         Pixel size in microns.
        #         """,
        # },
    }

    def __init__(self):
        raise RuntimeError(
            "RasterType objects are created automatically by ImageSource. Do not instantiate this class directly."
        )

    @classmethod
    def new(cls, name: str):
        """
        :meta private:
        """
        self = cls.__new__(cls)
        self._name = name
        self._sensor_type = None
        # Decide which attributes to use
        if self._name in self._raster_types_satellite_list["names"]:
            attrs = self._raster_types_satellite_list["attributes"]
            self._sensor_type = "satellite"
        elif self._name in self._raster_types_aerial_list:
            attrs = self._raster_types_aerial_list[self._name]
            self._sensor_type = "aerial"
        elif self._name == "Raster Dataset":
            attrs = {}
        else:
            rastertypes_list = self._raster_types_satellite_list["names"] + list(
                self._raster_types_aerial_list.keys()
            )
            rastertypes_list.sort()
            raise ValueError(
                f"Unknown raster type: {self._name}. Raster Type should be one of the following {rastertypes_list}"
            )

        # Dynamically create properties for attributes
        for attr_name, doc in attrs.items():
            private_name = f"_{attr_name}"
            setattr(self, private_name, None)
            self._add_dynamic_property(attr_name, private_name, doc)

        # Initialize core attributes
        # self._in_sr = None
        self.processing_template = None
        self.dem = None
        self.averagezdem = None
        self.constant_z = None
        self.zfactor = None
        self.zoffset = None
        self.correct_geoid = None
        self.estimate_flight_height = None
        self.is_altitude_flight_height = None
        self.minimum_flight_height = None
        self.stretch_type = None
        self.scale_factor = None
        self.valid_range = None
        return self

    @property
    def name(self):
        """Raster type name"""
        return self._name

    @name.setter
    def name(self, value):
        if self._name is not None:
            return
        self._name = value

    # -------------------------
    # Dynamic property creator
    # -------------------------
    def _add_dynamic_property(self, name, private_name, doc):
        """Creates a dynamic property with a docstring and overwrite prevention."""

        def getter(self):
            return getattr(self, private_name)

        def setter(self, value):
            # Prevent overwriting raster type name once set
            if private_name == "_name":
                if getattr(self, private_name, None) is not None:
                    raise AttributeError(f"'{name}' is read-only once set")

            setattr(self, private_name, value)

        getter.__doc__ = doc.strip() if doc else ""
        prop = property(getter, setter)
        setattr(self.__class__, name, prop)

    @property
    def attributes(self):
        """Returns all attributes of the raster type as a dictionary."""
        attrs = {}

        for name, value in vars(self).items():
            if name.startswith("_"):
                attrs[name[1:]] = value
            else:
                attrs[name] = value

        attrs.pop("sensor_type", None)
        return attrs


class ImageSource:
    """
    Represents an input dataset which can configured by a specific raster type.

    The class accepts a string value for a raster type at initialization. This
    creates a new :class:`~arcgis.raster.ImageSource` object. On this object a,
    corresponding :class:`~arcgis.raster.RasterType` instance is created and
    accessed as the :attr:`raster_type` property through which users can provide
    the input data for the dataset.

    The :class:`~arcgis.raster.RasterType` object encapsulates all input
    parameters that are specific to the selected sensor type and needs to be
    provided by the user.

    ====================================     ====================================================================
    **Parameter**                            **Description**
    ------------------------------------     --------------------------------------------------------------------
    raster_type_name                         Required string. Determines the *RasterType* of the input dataset.
                                             The raster type also defines the type-specific parameters present
                                             in the :attr:`raster_type` property.

                                             Choice list:

                                             | [
                                             | "ASTER", "Aerial", "DMCII", "DubaiSat-2", "Frame Camera", "GF-1 PMS", "GF-1 WFV", "GF-2 PMS",
                                             | "GRIB", "GeoEye-1", "HDF", "IKONOS", "Jilin-1", "KOMPSAT-2", "KOMPSAT-3", "Landsat 1-5 MSS",
                                             | "Landsat 4-5 TM", "Landsat 7 ETM+", "Landsat 8", "Landsat 9", "PlanetScope", "Pleiades NEO",
                                             | "Pleiades-1", "QuickBird", "RapidEye", "Raster Dataset", "SPOT 5", "SPOT 6", "SPOT 7"
                                             | "Sentinel-2", "SkySat", "Superview-1", "UAV/UAS", "WorldView-1", "WorldView-2", "WorldView-3",
                                             | "WorldView-4", "ZY3-CRESDA", "ZY3-SASMAC"
                                             | ]
    ====================================     ====================================================================

    .. code-block:: python

        # Usage Example 1: Create an ImageSource object for a UAV/UAS dataset.

        >>> from arcgis.raster import ImageSource

        >>> ds = ImageSource("UAV/UAS")
        >>> ds.input_data = "\\\\path\\to\\data\\image.tif"
        >>> ds.raster_type.camera_info = "\\\\path\\to\\data\\camera_info.csv"
        >>> ds.raster_type.gps_info = "\\\\path\\to\\data\\gps_info.csv"
        >>> ds.raster_type.attributes    #returns all attributes associated with the raster type
    """

    def __init__(self, raster_type_name: str):
        self._input_data = None
        self.raster_type = RasterType.new(raster_type_name)
        # self.byref = True

    # -------------------------
    # Core attributes
    # -------------------------

    @property
    def input_data(self):
        """
        Required, the list of input rasters to be added to the image collection being
        created. This can be any one of the following paths pointing to the raster
        dataset(s) or folder(s):

        - Shared data path (this path must be accessible by the server)
        - Local path (this path must be accessible by the server)
        - Datastore path (eg. */fileShares*, */cloudStores*)
        """
        return self._input_data

    @input_data.setter
    def input_data(self, value):
        self._input_data = value

    # -------------------------
    # Private Methods
    # -------------------------

    def _to_json(self):
        input_dict = {}
        raster_type_params_dict = {}
        _self_dict = {}

        for k, v in (
            copy.deepcopy(vars(self)) | copy.deepcopy(vars(self.raster_type))
        ).items():
            if v is not None:
                _self_dict[k] = v

        _self_dict.pop("raster_type", None)
        sensor_type = _self_dict.pop("_sensor_type", None)

        input_dict["input_data"] = _self_dict.pop("_input_data", None)
        # input_dict["in_sr"] = _self_dict.pop("in_sr", None)

        raster_type_name = _self_dict.pop("_name", None)

        def _to_camel_case(s):
            parts = s.split("_")
            if parts[0] == "":
                return parts[1].lower() + "".join(
                    word.capitalize() for word in parts[2:]
                )
            else:
                return parts[0].lower() + "".join(
                    word.capitalize() for word in parts[1:]
                )

        def _convert_keys(obj):
            if isinstance(obj, dict):
                return {_to_camel_case(k): _convert_keys(v) for k, v in obj.items()}
            else:
                return obj

        for k in list(_self_dict):
            if _self_dict[k] is None:
                del _self_dict[k]

        _self_dict = _convert_keys(_self_dict)

        if sensor_type == "aerial":
            if (
                raster_type_name == "UAV/UAS"
                or raster_type_name == "RedEdge"
                or raster_type_name == "Altum"
            ):
                if "gpsInfo" in _self_dict:
                    _self_dict["gps"] = _self_dict.pop("gpsInfo")
                if "cameraInfo" in _self_dict:
                    _self_dict["cameraProperties"] = _self_dict.pop("cameraInfo")
            if raster_type_name == "Aerial" or raster_type_name == "Frame Camera":
                if "cameraInfo" in _self_dict:
                    _self_dict["cameraTable"] = _self_dict.pop("cameraInfo")
        elif sensor_type == "satellite":
            if "pansharpenWeights" in _self_dict:
                _self_dict["pansharpenWeights"] = " ".join(
                    str(x) for x in _self_dict["pansharpenWeights"]
                )

        # def _is_path(value: str) -> bool:
        #     """Return True if the string looks like a valid file system path."""
        #     if os.path.isabs(value):
        #         return True
        #     if os.path.exists(value):
        #         return True
        #     if value.startswith("/fileShares") or value.startswith("/cloudStores") or value.startswith("/enterpriseDatabases"):
        #         return True
        #     return False

        for key, value in _self_dict.items():
            if isinstance(value, str):
                # if _is_path(value):
                #     _self_dict[key] = {"uri": value}
                if value.startswith("http://") or value.startswith("https://"):
                    _self_dict[key] = {"url": value}
                else:
                    _self_dict[key] = value
            elif isinstance(value, list) and len(value) > 0 and value[0]:
                if isinstance(value[0], str):
                    # if _is_path(value[0]):
                    #     _self_dict[key] = {"uris": value}
                    if value[0].startswith("http://") or value[0].startswith(
                        "https://"
                    ):
                        _self_dict[key] = {"urls": value}
                    else:
                        _self_dict[key] = value
                else:
                    _self_dict[key] = value
            else:
                _self_dict[key] = value

        raster_type_params_dict["rasterTypeName"] = raster_type_name
        raster_type_params_dict["rasterTypeParameters"] = _self_dict
        return input_dict, raster_type_params_dict
